template.declaration:
void Initialisation(){
  varTrackStatusArea[i].traindata.NID_ENGINE = msgVTDReceived[i].msg.NID_ENGINE;
  varTrackStatusArea[i].traindata.L_TRAIN = msgVTDReceived[i].L_TRAIN;
  // Other initialisation of local data!!!
  varTrackStatusArea[i].traindata.positionReport.M_MODE = FULLSUPERVISION;
  varTrackStatusArea[i].traindata.positionReport.trainIntegrity.Q_LENGTH = MONITORINGDEVICE;
}

// Clock needed by Communication Manager to ...
clock clkCM_MuteTimer;
// Clock needed by Communication Manager to ...
clock clkCM_SessionTimer;

// Timeout needed by Communication Manager to ...
const int MUTE_EXPIRED_TIMEOUT = 2 * 10; //in 0,1 s
// Timeout needed by Communication Manager to ...
const int SESSION_EXPIRED_TIMEOUT = 10 * 10;  //in 0,1 s


bool msgTPROK(){
return
(msgTPRReceived[i].msg.NID_ENGINE == varTrackStatusArea[i].traindata.NID_ENGINE&&
   // (msgTPRReceived[i].positionReport.trainIntegrity.Q_LENGTH == MONITORINGDEVICE || msgTPRReceived[i].positionReport.trainIntegrity.Q_LENGTH == DRIVER) &&     
       msgVTDReceived[i].L_TRAIN==TrainLengthSentToTM[i]);
//msgTPRReceived[i].positionReport.trainIntegrity.L_TRAININT == varTrackStatusArea[i].traindata.locationx.trainIntegrity.L_TRAININT);

}
bool msgVTDOK(){
  return 
    (msgVTDReceived[i].msg.NID_ENGINE == varTrackStatusArea[i].traindata.NID_ENGINE &&
     msgVTDReceived[i].L_TRAIN == varTrackStatusArea[i].traindata.locationx.trainIntegrity.L_TRAININT);
}

void CommunicationUp(){
  LOC_communicationTimerExpired = false;
}

void CommunicationDown(){
  LOC_communicationTimerExpired = true;
}

bool msgTPROK(){
return
(msgTPRReceived[i].msg.NID_ENGINE == varTrackStatusArea[i].traindata.NID_ENGINE&&
   // (msgTPRReceived[i].positionReport.trainIntegrity.Q_LENGTH == MONITORINGDEVICE || msgTPRReceived[i].positionReport.trainIntegrity.Q_LENGTH == DRIVER) &&     
       msgVTDReceived[i].L_TRAIN==TrainLengthSentToTM[i]);
//msgTPRReceived[i].positionReport.trainIntegrity.L_TRAININT == varTrackStatusArea[i].traindata.locationx.trainIntegrity.L_TRAININT);

}


bool msgVTDOK(){
  return 
    (msgVTDReceived[i].msg.NID_ENGINE == varTrackStatusArea[i].traindata.NID_ENGINE &&
//     msgVTDReceived[i].L_TRAIN == varTrackStatusArea[i].traindata.location.trainIntegrity.L_TRAININT);
     msgVTDReceived[i].L_TRAIN == varTrackStatusArea[i].traindata.L_TRAIN);
}

void TPRUpdateTrainData(){
  // Other updates of local data!!!
  varTrackStatusArea[i].traindata.positionReport.last.D_LRBG = msgTPRReceived[i].positionReport.last.D_LRBG;//ADR very important but missed in original
  varTrackStatusArea[i].traindata.positionReport.trainIntegrity.Q_LENGTH = msgTPRReceived[i].positionReport.trainIntegrity.Q_LENGTH; // TPRManagement does not currently provide this field which is needed according to the specifications
  varTrackStatusArea[i].traindata.positionReport.last.L_DOUBTOVER = msgTPRReceived[i].positionReport.last.L_DOUBTOVER;
  varTrackStatusArea[i].traindata.locationx.trainIntegrity.L_TRAININT = msgTPRReceived[i].positionReport.trainIntegrity.L_TRAININT;
  // We should also update at least Position data structure (CRE and MaxSFE) of the train (and possibly the other fields if they are necessary for the model to work)
}
bool IntegrityConfirmed(){
  return
    ((varTrackStatusArea[i].traindata.positionReport.M_MODE == FULLSUPERVISION || varTrackStatusArea[i].traindata.positionReport.M_MODE == ONSIGHT) && 
     (varTrackStatusArea[i].traindata.positionReport.trainIntegrity.Q_LENGTH == MONITORINGDEVICE || 
      (varTrackStatusArea[i].traindata.positionReport.trainIntegrity.Q_LENGTH == DRIVER && INFRASTRUCTURE.RBC.INTEGRITY_DRIVER_ACCEPATACNCE)));
}
bool IntegrityNonConfirmed(){
  return
     (varTrackStatusArea[i].traindata.positionReport.trainIntegrity.Q_LENGTH == NOINFORMATION || 
      varTrackStatusArea[i].traindata.positionReport.trainIntegrity.Q_LENGTH == LOST || 
      (varTrackStatusArea[i].traindata.positionReport.trainIntegrity.Q_LENGTH == DRIVER && !INFRASTRUCTURE.RBC.INTEGRITY_DRIVER_ACCEPATACNCE));
}

bool VTDTrainExtended(){
  return 
    (msgVTDReceived[i].L_TRAIN > varTrackStatusArea[i].traindata.L_TRAIN);
}
bool ExtensionOK(){
  return true; // Implement the correct test and the corresponding action when this fails!!! REQ-TrainLoc-13 & REQ-TrainLoc-14
}

void VTDUpdateTrainData(){
  varTrackStatusArea[i].traindata.L_TRAIN = msgVTDReceived[i].L_TRAIN;
  varTrackStatusArea[i].traindata.locationx.CRE = (varTrackStatusArea[i].traindata.positionReport.last.L_DOUBTOVER - varTrackStatusArea[i].traindata.L_TRAIN);
}

void UpdateL_TRAIN(){
  varTrackStatusArea[i].traindata.L_TRAIN = msgVTDReceived[i].L_TRAIN; // THIS MUST BE DONE CORRECTLY
}

void UpdateSFE()//X2Rail 5 page 25
{
 varTrackStatusArea[i].traindata.locationx.MaxSFE = varTrackStatusArea[i].traindata.positionReport.last.D_LRBG+varTrackStatusArea[i].traindata.positionReport.last.L_DOUBTUNDER;//ADR need D_LRBG  also
}

void UpdateCRE()//X2Rail 5 page 25
{

 varTrackStatusArea[i].traindata.locationx.CRE = (varTrackStatusArea[i].traindata.positionReport.last.D_LRBG-varTrackStatusArea[i].traindata.positionReport.last.L_DOUBTOVER - varTrackStatusArea[i].traindata.locationx.trainIntegrity.L_TRAININT);//ADR change
}

