bool requestPointClear() {
int j, k;
    for (j = 0; j < m; j++) {
        int p = Route[i].pointControlled[j].IDPoint;

        // Check only used points (IDPoint ≠ -1)
        if (p != -1) {
            int32_t pointStart = pointData[p].pointLocW;
            int32_t pointEnd   = pointData[p].pointLocE;

            for (k = 0; k < N_TRAINS; k++) {
                // Skip checking against itself
                if (i==0){
                return true;}
                else if (k != i) {

                    int32_t occupiedStart = varTrackStatusArea[k].extent.start;
                    int32_t occupiedEnd   = varTrackStatusArea[k].extent.end;
                    int32_t MA   = MA[k].EoA;

                    // If there is overlap with another train's reserved area
                    if ((!(pointEnd < occupiedStart || pointStart > occupiedEnd))) {
                        return false;
                    }
                }
            }
        }
    }
    return true; // All used points are clear from other reserved areas
}

