bool extent_overlaps_with(int j)
{
    return ((varTrackStatusArea[j].extent.end >= varTrackStatusArea[i].extent.start && varTrackStatusArea[j].extent.end <= varTrackStatusArea[i].extent.end)||
            (varTrackStatusArea[j].extent.start <= varTrackStatusArea[i].extent.end && varTrackStatusArea[i].extent.end <= varTrackStatusArea[j].extent.end));  
// TSA i only checks whether its end enters another TSA j and leaves the symmetric condition to the corresponding conflict check done by TSA j.
}

bool Conflict(){
 // This must check if the current TSA for train "i" overlaps with the TSA of some other train.
  int j;
  for (j=0; j < N_TRAINS; j++)
   { 
     if ( j!=i && extent_overlaps_with(j)&&varTrackStatusArea[i].extent.end>start_loc_int&&varTrackStatusArea[j].extent.end>start_loc_int) {
        return true;
     }  
   }
return false;  
}
