void updateRSA(){
    int j;
    varReservedStatusArea[i].extent.end = Route[i].end;


    //Loop through all trains to see if any valid trains are inside the current route.

    for ( j = 0; j <  N_TRAINS; j++) {

        if ((varReservedStatusArea[i].extent.end+800*10000 >= varReservedStatusArea[j].extent.start) && varReservedStatusArea[j].extent.start>varReservedStatusArea[i].extent.start) {
           varReservedStatusArea[i].extent.end= intermediateTSAstart[j];
        }
    }




  for (j = 0; j < m; j++) {
        int pointID = Route[i].pointControlled[j].IDPoint;
        if (pointID != -1) {
              if(varTrackStatusArea[i].extent.start>pointData[pointID].pointLocE)
                    {Route[i].pointControlled[j].IDPoint=-1;}
         }
   }

}



bool checkPointsReserved() {
int j, k;
    for (j = 0; j < m; j++) {
        int p = Route[i].pointControlled[j].IDPoint;

        // Check only used points (IDPoint ≠ -1)
        if (p != -1) {
            int32_t pointStart = pointData[p].pointLocW;
            int32_t pointEnd   = pointData[p].pointLocE;

            for (k = 0; k < N_TRAINS; k++) {
                // Skip checking against itself
                if (i==0){
                return true;}
                else if (k != i) {
                    int32_t reservedStart = varReservedStatusArea[k].extent.start;
                    int32_t reservedEnd   = varReservedStatusArea[k].extent.end;

                    // If there is overlap with another train's reserved area
                    if ((!(pointEnd < reservedStart || pointStart > reservedEnd))) {
                        return false;
                    }
                }
            }
        }
    }
    return true; // All used points are clear from other reserved areas
}

