bool noConflict= true;
int32_t pointStart;
int32_t pointEnd;
int p;

void PointNotConflict() {

int j, k;

   for (j : int[0, m]) {
        p = Route[i].pointControlled[j].IDPoint;

        if (p != -1) {   // only process valid points
             pointStart = pointData[p].pointLocW;
             pointEnd   = pointData[p].pointLocE;

            for  (k : int[0, N_TRAINS-1]) {
                if (i==0){
                noConflict = true; }
                if (k != i) {  // skip itself
                    int32_t occupiedStart =  varTrackStatusArea[k].extent.start;//P_int[k] - 900*10000;//
                    int32_t occupiedEnd   =   varTrackStatusArea[k].extent.end;//P_int[k];//
                    int32_t reservedStart = varReservedStatusArea[k].extent.start;
                    int32_t reservedEnd   = varReservedStatusArea[k].extent.end;


                    if (!(pointEnd < occupiedStart || pointStart > occupiedEnd)||(!(pointEnd < reservedStart || pointStart > reservedEnd))) {
                        noConflict = false;   // mark conflict
                    }
                }
            }
        }
    }

  // true if no conflict, false if conflict detected
}

