MSGPositionReport FillTrainPositionReport(){

   MSGPositionReport msgPositionReport ;
   msgPositionReport.msg.NID_ENGINE = ID_Train ;
   msgPositionReport.positionReport.M_MODE = mode[ID_Train] ;
   msgPositionReport.positionReport.trainIntegrity.Q_LENGTH = TPR_IntegrityInfo ;
   msgPositionReport.positionReport.V_TRAIN = TPRReceivedSpeed ;
   msgPositionReport.positionReport.last.L_DOUBTOVER = DoubtL ;  //subset 26, part7, page 51, in our case 0, doubts are not considered
   msgPositionReport.positionReport.last.L_DOUBTUNDER = DoubtH;
   msgPositionReport.positionReport.last.D_LRBG = TPRReceivedPosition;
   msgPositionReport.positionReport.last.NID_LRBG = TPRReceivedLastLRBG;
      if (isFirstTPR){
        isFirstTPR = false ;
       msgPositionReport.positionReport.lastConfirmed.L_DOUBTOVER = 0 ;  //subset 26, part7, page 51, in our case 0, doubts are not considered
       msgPositionReport.positionReport.lastConfirmed.L_DOUBTUNDER = 0;
       msgPositionReport.positionReport.lastConfirmed.D_LRBG = -1;
       msgPositionReport.positionReport.lastConfirmed.NID_LRBG = -1;
       if (TPR_IntegrityInfo==MONITORINGDEVICE) {   
           msgPositionReport.positionReport.trainIntegrity.L_TRAININT = TrainLengthSentToTM[ID_Train];//msgPositionReport.positionReport.l.D_LRBG; //traveled distance  
           LastConfirmedPosition.L_DOUBTOVER =msgPositionReport.positionReport.last.L_DOUBTOVER ;  //subset 26, part7, page 51, in our case 0, doubts are not considered
           LastConfirmedPosition.L_DOUBTUNDER =msgPositionReport.positionReport.last.L_DOUBTUNDER;
           LastConfirmedPosition.D_LRBG =msgPositionReport.positionReport.last.D_LRBG;
           LastConfirmedPosition.NID_LRBG =msgPositionReport.positionReport.last.NID_LRBG;

            }
        else { // can never happen
           msgPositionReport.positionReport.trainIntegrity.L_TRAININT = -1 ;
            LastConfirmedPosition.L_DOUBTOVER = 0 ;  //subset 26, part7, page 51, in our case 0, doubts are not considered
            LastConfirmedPosition.L_DOUBTUNDER = 0;
            LastConfirmedPosition.D_LRBG = -1;
            LastConfirmedPosition.NID_LRBG = -1;
            }
} //not first TPR
    else {
           if (LastConfirmedPosition.D_LRBG == -1)
         {
          msgPositionReport.positionReport.trainIntegrity.L_TRAININT =msgPositionReport.positionReport.last.D_LRBG ; }//traveled distance
           else
         {
          msgPositionReport.positionReport.trainIntegrity.L_TRAININT =msgPositionReport.positionReport.last.D_LRBG - (LastConfirmedPosition.D_LRBG - LastConfirmedPosition.L_DOUBTOVER-TrainLengthSentToTM[ID_Train]) ;
         }
          msgPositionReport.positionReport.lastConfirmed.L_DOUBTOVER = LastConfirmedPosition.L_DOUBTOVER ;  //subset 26, part7, page 51, in our case 0, doubts are not considered
          msgPositionReport.positionReport.lastConfirmed.L_DOUBTUNDER = LastConfirmedPosition.L_DOUBTUNDER;
          msgPositionReport.positionReport.lastConfirmed.D_LRBG = LastConfirmedPosition.D_LRBG;
          msgPositionReport.positionReport.lastConfirmed.NID_LRBG = LastConfirmedPosition.NID_LRBG;           

       if (TPR_IntegrityInfo==MONITORINGDEVICE) {   

           LastConfirmedPosition.L_DOUBTOVER =msgPositionReport.positionReport.last.L_DOUBTOVER ;  //subset 26, part7, page 51, in our case 0, doubts are not considered
           LastConfirmedPosition.L_DOUBTUNDER =msgPositionReport.positionReport.last.L_DOUBTUNDER;
           LastConfirmedPosition.D_LRBG =msgPositionReport.positionReport.last.D_LRBG;
           LastConfirmedPosition.NID_LRBG =msgPositionReport.positionReport.last.NID_LRBG;
    }   

}
 //  LastPositionReport =msgPositionReport ;    

    return msgPositionReport; 
/*
    TrainLRBGSentToTM [ID_Train] = TPRReceivedLastLRBG;     TrainLocationSentToTM [ID_Train] = TPRReceivedPosition ;
    TrainSpeedSentToTM [ID_Train] = TPRReceivedSpeed ;     TrainIntegritySentToTM[ID_Train] = TPR_IntegrityInfo ;
*/
}

